diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 7bff13d59528..3b4dbdb1a9b5 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -1850,6 +1850,78 @@ static Value *simplifyAndOrOfFCmps(const SimplifyQuery &Q, FCmpInst *LHS,
                  : ConstantInt::getBool(LHS->getType(), !IsAnd);
   }

+  // Check for two comparisons of the same value against different constants.
+  // e.g., (X < C0) | (X < C1) where C0 < C1 simplifies to (X < C1)
+  // For AND, we take the more restrictive comparison.
+  const APFloat *C0, *C1;
+  Value *LHSVal = nullptr, *RHSVal = nullptr;
+  FCmpInst::Predicate Pred0, Pred1;
+
+  // Normalize so LHSVal is the common compared value and RHSVal is the constant
+  // Handle cases like: (X < C) and (C > X) by normalizing to consistent form
+  auto normalizeFCmp = [&](FCmpInst *Cmp, Value *&Val, const APFloat *&Const,
+                           FCmpInst::Predicate &Pred) -> bool {
+    if (match(Cmp->getOperand(1), m_APFloat(Const))) {
+      Val = Cmp->getOperand(0);
+      Pred = Cmp->getPredicate();
+      return true;
+    }
+    if (match(Cmp->getOperand(0), m_APFloat(Const))) {
+      Val = Cmp->getOperand(1);
+      Pred = FCmpInst::getSwappedPredicate(Cmp->getPredicate());
+      return true;
+    }
+    return false;
+  };
+
+  if (normalizeFCmp(LHS, LHSVal, C0, Pred0) && normalizeFCmp(RHS, RHSVal, C1, Pred1) &&
+      LHSVal == RHSVal && &C0->getSemantics() == &C1->getSemantics()) {
+    // Both compare same value to constants with same semantics
+
+    // Handle ordered less-than comparisons (OLT, OLE)
+    bool IsLess0 = (Pred0 == FCmpInst::FCMP_OLT || Pred0 == FCmpInst::FCMP_OLE);
+    bool IsGreater0 = (Pred0 == FCmpInst::FCMP_OGT || Pred0 == FCmpInst::FCMP_OGE);
+    bool IsLess1 = (Pred1 == FCmpInst::FCMP_OLT || Pred1 == FCmpInst::FCMP_OLE);
+    bool IsGreater1 = (Pred1 == FCmpInst::FCMP_OGT || Pred1 == FCmpInst::FCMP_OGE);
+
+    // For OR: take the comparison that covers more values (less restrictive)
+    // For AND: take the comparison that covers fewer values (more restrictive)
+    if (IsLess0 && IsLess1) {
+      // (X < C0) | (X < C1) -> X < max(C0, C1)
+      // (X < C0) & (X < C1) -> X < min(C0, C1)
+      bool C0IsLess = C0->compare(*C1) == APFloat::cmpLessThan;
+      FCmpInst *Result = IsAnd ? (C0IsLess ? LHS : RHS) : (C0IsLess ? RHS : LHS);
+      // Need to use the correct predicate (OLE vs OLT)
+      if (IsAnd) {
+        // For AND, we need the more restrictive one (smaller constant)
+        // If predicates differ (one is OLT, one is OLE), we need OLT for smaller
+        if (Pred0 == Pred1 || C0IsLess == (Pred0 == FCmpInst::FCMP_OLT))
+          return Result;
+      } else {
+        // For OR, we need the less restrictive one (larger constant)
+        // If predicates differ, we need OLE for larger
+        if (Pred0 == Pred1 || C0IsLess == (Pred0 == FCmpInst::FCMP_OLE))
+          return Result;
+      }
+    }
+
+    if (IsGreater0 && IsGreater1) {
+      // (X > C0) | (X > C1) -> X > min(C0, C1)
+      // (X > C0) & (X > C1) -> X > max(C0, C1)
+      bool C0IsLess = C0->compare(*C1) == APFloat::cmpLessThan;
+      FCmpInst *Result = IsAnd ? (C0IsLess ? RHS : LHS) : (C0IsLess ? LHS : RHS);
+      if (IsAnd) {
+        // For AND, we need the more restrictive one (larger constant)
+        if (Pred0 == Pred1 || C0IsLess == (Pred0 == FCmpInst::FCMP_OGT))
+          return Result;
+      } else {
+        // For OR, we need the less restrictive one (smaller constant)
+        if (Pred0 == Pred1 || C0IsLess == (Pred0 == FCmpInst::FCMP_OGE))
+          return Result;
+      }
+    }
+  }
+
   return nullptr;
 }

